css:
.loader {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
   width: 28px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: var(--loader-color, #9333ea);
   animation: l2 1.5s infinite;
}
@keyframes l2  {
  0%, 100%{transform:translate(-35px);
  box-shadow: 0 0 var(--loader-secondary-color, #f0abfc), 0 0 var(--loader-secondary-color, #f0abfc)}
40% {transform:translate( 35px);
  box-shadow: -15px 0 var(--loader-secondary-color, #f0abfc),-30px 0 var(--loader-secondary-color, #f0abfc)}
50% {transform:translate( 35px);
  box-shadow: 0 0 var(--loader-secondary-color, #f0abfc), 0 0 var(--loader-secondary-color, #f0abfc)}
90% {transform:translate(-35px);
  box-shadow: 15px 0 var(--loader-secondary-color, #f0abfc), 30px 0 var(--loader-secondary-color, #f0abfc)}
}
